var COURSE_PL_PT = [{day: 1, title: `Pierwsze powitania`, title_native: `Primeiros cumprimentos`, focus: `Zaczniesz od najprostszych zwrotów używanych po przylocie do Lizbony lub Porto. Celem jest umieć przywitać się, pożegnać i zareagować uprzejmie w codziennych sytuacjach.`, vocab: [{pt: `olá`, pl: `cześć / dzień dobry`, ipa: `/oˈla/`},{pt: `bom dia`, pl: `dzień dobry`, ipa: `/bõ ˈdi.a/`},{pt: `boa tarde`, pl: `dobry wieczór / dobre popołudnie`, ipa: `/ˈbo.a ˈtaʁ.dɨ/`},{pt: `boa noite`, pl: `dobry wieczór / dobranoc`, ipa: `/ˈbo.a ˈnoj.tɨ/`},{pt: `adeus`, pl: `do widzenia`, ipa: `/ɐˈdewʃ/`},{pt: `tchau`, pl: `pa`, ipa: `/ˈtʃaw/`},{pt: `por favor`, pl: `proszę`, ipa: `/puʁ fɐˈvoʁ/`},{pt: `obrigado`, pl: `dziękuję, mówi mężczyzna`, ipa: `/obɾiˈɡa.du/`},{pt: `obrigada`, pl: `dziękuję, mówi kobieta`, ipa: `/obɾiˈɡa.dɐ/`},{pt: `sim`, pl: `tak`, ipa: `/sĩ/`}], phrases: [{pt: `Olá, bom dia.`, pl: `Cześć, dzień dobry.`, ipa: `/oˈla bõ ˈdi.a/`},{pt: `Boa tarde, tudo bem?`, pl: `Dzień dobry, wszystko dobrze?`, ipa: `/ˈbo.a ˈtaʁ.dɨ ˈtu.du bẽj/`},{pt: `Muito obrigado.`, pl: `Bardzo dziękuję, mówi mężczyzna.`, ipa: `/ˈmũj.tu obɾiˈɡa.du/`},{pt: `Muito obrigada.`, pl: `Bardzo dziękuję, mówi kobieta.`, ipa: `/ˈmũj.tu obɾiˈɡa.dɐ/`},{pt: `Até logo.`, pl: `Do zobaczenia później.`, ipa: `/ɐˈtɛ ˈlo.ɡu/`},{pt: `Por favor.`, pl: `Proszę.`, ipa: `/puʁ fɐˈvoʁ/`}], grammar: `W portugalskim forma „obrigado” zmienia się w zależności od osoby mówiącej: mężczyzna mówi „obrigado”, kobieta mówi „obrigada”. Zwrot „bom dia” używany jest rano i przed południem, a „boa tarde” po południu. W Portugalii często słyszysz „olá” jako neutralne, przyjazne powitanie.`, practice: [`Powiedz po portugalsku „dzień dobry” i „do widzenia”.`,`Wybierz właściwą formę: jesteś kobietą i chcesz powiedzieć „dziękuję”.`,`Połącz „olá” z uprzejmym „por favor” w krótkim zdaniu.`,`Przećwicz trzy razy: „Boa tarde, tudo bem?”.`,`Wyobraź sobie, że wchodzisz do kawiarni w Porto i przywitaj się z obsługą.`]},{day: 2, title: `Przedstawianie się`, title_native: `Apresentar-se`, focus: `Nauczysz się mówić, jak masz na imię i skąd jesteś. Przyda się to w hostelu w Lizbonie, podczas wycieczki po Porto albo przy pierwszej rozmowie z lokalną osobą.`, vocab: [{pt: `eu`, pl: `ja`, ipa: `/ew/`},{pt: `tu`, pl: `ty`, ipa: `/tu/`},{pt: `você`, pl: `pan / pani / ty, w Brazylii`, ipa: `/voˈse/`},{pt: `nome`, pl: `imię`, ipa: `/ˈno.mɨ/`},{pt: `chamar-se`, pl: `nazywać się`, ipa: `/ʃɐˈmaʁ sɨ/`},{pt: `ser`, pl: `być`, ipa: `/seʁ/`},{pt: `sou`, pl: `jestem`, ipa: `/so/`},{pt: `Polónia`, pl: `Polska`, ipa: `/puˈlɔ.njɐ/`},{pt: `português`, pl: `portugalski`, ipa: `/puʁtuˈɡeʃ/`},{pt: `prazer`, pl: `miło mi`, ipa: `/pɾɐˈzeʁ/`}], phrases: [{pt: `Como se chama?`, pl: `Jak się pan / pani nazywa?`, ipa: `/ˈko.mu sɨ ˈʃa.mɐ/`},{pt: `Chamo-me Anna.`, pl: `Nazywam się Anna.`, ipa: `/ˈʃa.mu mɨ ˈanɐ/`},{pt: `Sou da Polónia.`, pl: `Jestem z Polski.`, ipa: `/so dɐ puˈlɔ.njɐ/`},{pt: `Muito prazer.`, pl: `Bardzo mi miło.`, ipa: `/ˈmũj.tu pɾɐˈzeʁ/`},{pt: `Fala português?`, pl: `Czy mówi pan / pani po portugalsku?`, ipa: `/ˈfa.lɐ puʁtuˈɡeʃ/`},{pt: `Falo um pouco.`, pl: `Mówię trochę.`, ipa: `/ˈfa.lu ũ ˈpo.ku/`}], grammar: `Czasownik „ser” oznacza „być” przy stałych informacjach, takich jak narodowość, pochodzenie lub zawód. „Sou da Polónia” dosłownie znaczy „jestem z Polski”. W Portugalii „Como se chama?” brzmi grzeczniej niż bezpośrednie „Como te chamas?”, które pasuje do rozmów nieformalnych.`, practice: [`Powiedz: „Nazywam się…” po portugalsku.`,`Powiedz: „Jestem z Polski”.`,`Zapytaj kogoś grzecznie o imię.`,`Odpowiedz na pytanie „Fala português?” słowami „Falo um pouco”.`,`Zbuduj mini-dialog: powitanie, imię, pochodzenie, „miło mi”.`]},{day: 3, title: `Uprzejme podstawy`, title_native: `Frases educadas básicas`, focus: `W podróży po Portugalii uprzejmość bardzo pomaga, zwłaszcza w sklepach, hotelach i restauracjach. Dziś nauczysz się przepraszać, prosić i reagować na podziękowania.`, vocab: [{pt: `desculpe`, pl: `przepraszam, formalnie`, ipa: `/dɨʃˈkul.pɨ/`},{pt: `desculpa`, pl: `przepraszam, nieformalnie`, ipa: `/dɨʃˈkul.pɐ/`},{pt: `com licença`, pl: `przepraszam, proszę przepuścić`, ipa: `/kõ liˈsẽ.sɐ/`},{pt: `nada`, pl: `nic`, ipa: `/ˈna.dɐ/`},{pt: `de nada`, pl: `nie ma za co`, ipa: `/dɨ ˈna.dɐ/`},{pt: `claro`, pl: `oczywiście`, ipa: `/ˈkla.ɾu/`},{pt: `talvez`, pl: `może`, ipa: `/tɐlˈveʃ/`},{pt: `não`, pl: `nie`, ipa: `/nɐ̃w/`},{pt: `bem`, pl: `dobrze`, ipa: `/bẽj/`},{pt: `mal`, pl: `źle`, ipa: `/maɫ/`}], phrases: [{pt: `Desculpe, por favor.`, pl: `Przepraszam, proszę.`, ipa: `/dɨʃˈkul.pɨ puʁ fɐˈvoʁ/`},{pt: `Com licença.`, pl: `Przepraszam, proszę mnie przepuścić.`, ipa: `/kõ liˈsẽ.sɐ/`},{pt: `De nada.`, pl: `Nie ma za co.`, ipa: `/dɨ ˈna.dɐ/`},{pt: `Está bem.`, pl: `W porządku.`, ipa: `/ʃˈta bẽj/`},{pt: `Não há problema.`, pl: `Nie ma problemu.`, ipa: `/nɐ̃w a pɾuˈble.mɐ/`},{pt: `Claro, obrigado.`, pl: `Oczywiście, dziękuję.`, ipa: `/ˈkla.ɾu obɾiˈɡa.du/`}], grammar: `„Desculpe” to bezpieczna forma grzecznościowa, której możesz użyć wobec obcych osób. „Com licença” przydaje się, gdy chcesz przejść obok kogoś w metrze, sklepie lub restauracji. W Portugalii krótkie „Está bem” często znaczy „dobrze”, „okej” albo „w porządku”.`, practice: [`Powiedz „przepraszam” w formalnej sytuacji.`,`Powiedz „nie ma za co” po portugalsku.`,`Użyj „com licença” w zdaniu sytuacyjnym.`,`Przećwicz reakcję: ktoś mówi „obrigado”, ty odpowiadasz „de nada”.`,`Wyobraź sobie zatłoczony tramwaj w Lizbonie i poproś o przejście.`]},{day: 4, title: `Liczby od zera do dwudziestu`, title_native: `Números de zero a vinte`, focus: `Liczby są potrzebne przy płaceniu, zamawianiu, pytaniu o pokój i kupowaniu biletów. Dziś nauczysz się podstawowych liczb używanych w codziennych sytuacjach w Brazylii i Portugalii.`, vocab: [{pt: `zero`, pl: `zero`, ipa: `/ˈzɛ.ɾu/`},{pt: `um`, pl: `jeden`, ipa: `/ũ/`},{pt: `uma`, pl: `jedna`, ipa: `/ˈu.mɐ/`},{pt: `dois`, pl: `dwa`, ipa: `/dojʃ/`},{pt: `duas`, pl: `dwie`, ipa: `/ˈdu.ɐʃ/`},{pt: `três`, pl: `trzy`, ipa: `/tɾeʃ/`},{pt: `quatro`, pl: `cztery`, ipa: `/ˈkwa.tɾu/`},{pt: `cinco`, pl: `pięć`, ipa: `/ˈsĩ.ku/`},{pt: `dez`, pl: `dziesięć`, ipa: `/deʃ/`},{pt: `vinte`, pl: `dwadzieścia`, ipa: `/ˈvĩ.tɨ/`}], phrases: [{pt: `Um café, por favor.`, pl: `Jedną kawę, proszę.`, ipa: `/ũ kɐˈfɛ puʁ fɐˈvoʁ/`},{pt: `Duas águas, por favor.`, pl: `Dwie wody, proszę.`, ipa: `/ˈdu.ɐʃ ˈa.ɡwɐʃ puʁ fɐˈvoʁ/`},{pt: `Tenho três malas.`, pl: `Mam trzy walizki.`, ipa: `/ˈte.ɲu tɾeʃ ˈma.lɐʃ/`},{pt: `São dez euros.`, pl: `To dziesięć euro.`, ipa: `/sɐ̃w deʃ ˈew.ɾuʃ/`},{pt: `Quero quatro bilhetes.`, pl: `Chcę cztery bilety.`, ipa: `/ˈkɛ.ɾu ˈkwa.tɾu biˈʎe.tɨʃ/`},{pt: `Número vinte.`, pl: `Numer dwadzieścia.`, ipa: `/ˈnu.mɨ.ɾu ˈvĩ.tɨ/`}], grammar: `W portugalskim liczebnik „jeden” ma rodzaj: „um” przed rzeczownikiem męskim i „uma” przed żeńskim. Podobnie „dois” i „duas” zależą od rodzaju rzeczownika. Na przykład „um café”, ale „uma água”.`, practice: [`Policz po portugalsku od 0 do 10.`,`Powiedz „dwie wody, proszę”.`,`Powiedz, że masz trzy walizki.`,`Zapisz po portugalsku liczby: 1, 2, 4, 10, 20.`,`Zamów jedną kawę i użyj „por favor”.`]},{day: 5, title: `Pytania podstawowe`, title_native: `Perguntas básicas`, focus: `W Coimbrze, Rio de Janeiro czy Faro często trzeba szybko zapytać „gdzie”, „ile” albo „kiedy”. Dziś poznasz najważniejsze słowa pytające dla podróżnika.`, vocab: [{pt: `onde`, pl: `gdzie`, ipa: `/ˈõ.dɨ/`},{pt: `quando`, pl: `kiedy`, ipa: `/ˈkwɐ̃.du/`},{pt: `quanto`, pl: `ile, męskie`, ipa: `/ˈkwɐ̃.tu/`},{pt: `quanta`, pl: `ile, żeńskie`, ipa: `/ˈkwɐ̃.tɐ/`},{pt: `quem`, pl: `kto`, ipa: `/kẽj/`},{pt: `o quê`, pl: `co`, ipa: `/u ke/`},{pt: `porquê`, pl: `dlaczego`, ipa: `/puʁˈke/`},{pt: `como`, pl: `jak`, ipa: `/ˈko.mu/`},{pt: `aqui`, pl: `tutaj`, ipa: `/ɐˈki/`},{pt: `ali`, pl: `tam`, ipa: `/ɐˈli/`}], phrases: [{pt: `Onde fica o hotel?`, pl: `Gdzie znajduje się hotel?`, ipa: `/ˈõ.dɨ ˈfi.kɐ u oˈtɛɫ/`},{pt: `Quanto custa?`, pl: `Ile to kosztuje?`, ipa: `/ˈkwɐ̃.tu ˈkuʃ.tɐ/`},{pt: `Quando sai o comboio?`, pl: `Kiedy odjeżdża pociąg?`, ipa: `/ˈkwɐ̃.du saj u kõˈboj.u/`},{pt: `Como chego ao centro?`, pl: `Jak dotrę do centrum?`, ipa: `/ˈko.mu ˈʃe.ɡu aw ˈsẽ.tɾu/`},{pt: `O que é isto?`, pl: `Co to jest?`, ipa: `/u ke ɛ ˈiʃ.tu/`},{pt: `Quem fala inglês?`, pl: `Kto mówi po angielsku?`, ipa: `/kẽj ˈfa.lɐ ĩˈɡleʃ/`}], grammar: `Pytania w portugalskim często mają taki sam szyk jak zdania oznajmujące, a intonacja pokazuje, że pytasz. „Onde fica…” jest bardzo użyteczne, bo znaczy „gdzie znajduje się…”. W Portugalii słowo „comboio” oznacza pociąg, a w Brazylii częściej używa się „trem”.`, practice: [`Zapytaj, gdzie jest hotel.`,`Zapytaj, ile coś kosztuje.`,`Zapytaj, kiedy odjeżdża pociąg.`,`Użyj „como” w pytaniu o drogę do centrum.`,`Wskaż przedmiot i zapytaj „Co to jest?”.`]},{day: 6, title: `Lotnisko i przylot`, title_native: `Aeroporto e chegada`, focus: `Po przylocie do Lizbony, Porto lub São Paulo musisz rozumieć podstawowe słowa z lotniska. Dziś ćwiczysz bagaż, paszport, odprawę i wyjście.`, vocab: [{pt: `aeroporto`, pl: `lotnisko`, ipa: `/ɐ.e.ɾuˈpɔʁ.tu/`},{pt: `passaporte`, pl: `paszport`, ipa: `/pɐ.sɐˈpɔʁ.tɨ/`},{pt: `bagagem`, pl: `bagaż`, ipa: `/bɐˈɡa.ʒɐ̃j/`},{pt: `mala`, pl: `walizka`, ipa: `/ˈma.lɐ/`},{pt: `voo`, pl: `lot`, ipa: `/vo/`},{pt: `chegada`, pl: `przylot`, ipa: `/ʃɨˈɡa.dɐ/`},{pt: `partida`, pl: `odlot`, ipa: `/pɐʁˈti.dɐ/`},{pt: `saída`, pl: `wyjście`, ipa: `/sɐˈi.dɐ/`},{pt: `alfândega`, pl: `urząd celny`, ipa: `/aɫˈfɐ̃.dɨ.ɡɐ/`},{pt: `bilhete`, pl: `bilet`, ipa: `/biˈʎe.tɨ/`}], phrases: [{pt: `Onde está a saída?`, pl: `Gdzie jest wyjście?`, ipa: `/ˈõ.dɨ ʃˈta ɐ sɐˈi.dɐ/`},{pt: `Tenho uma mala.`, pl: `Mam jedną walizkę.`, ipa: `/ˈte.ɲu ˈu.mɐ ˈma.lɐ/`},{pt: `Perdi a minha bagagem.`, pl: `Zgubiłem / zgubiłam mój bagaż.`, ipa: `/ˈpɛʁ.di ɐ ˈmi.ɲɐ bɐˈɡa.ʒɐ̃j/`},{pt: `Aqui está o passaporte.`, pl: `Oto paszport.`, ipa: `/ɐˈki ʃˈta u pɐ.sɐˈpɔʁ.tɨ/`},{pt: `Qual é o número do voo?`, pl: `Jaki jest numer lotu?`, ipa: `/kwaɫ ɛ u ˈnu.mɨ.ɾu du vo/`},{pt: `Preciso de ajuda.`, pl: `Potrzebuję pomocy.`, ipa: `/pɾɨˈsi.zu dɨ ɐjˈu.dɐ/`}], grammar: `„Tenho” znaczy „mam” i przyda się w wielu sytuacjach podróżnych. „Preciso de…” oznacza „potrzebuję…” i łączy się z rzeczownikiem, na przykład „Preciso de ajuda”. W Portugalii „aqui está…” jest naturalnym sposobem podania dokumentu lub biletu.`, practice: [`Powiedz, że masz jedną walizkę.`,`Zapytaj, gdzie jest wyjście.`,`Powiedz, że potrzebujesz pomocy.`,`Podaj paszport słowami „Aqui está o passaporte”.`,`Stwórz krótką scenkę przy kontroli paszportowej.`]},{day: 7, title: `Hotel i zameldowanie`, title_native: `Hotel e check-in`, focus: `Dziś przygotujesz się do zameldowania w hotelu w Porto lub Salvadorze. Nauczysz się mówić o rezerwacji, pokoju, kluczu i dokumencie.`, vocab: [{pt: `hotel`, pl: `hotel`, ipa: `/oˈtɛɫ/`},{pt: `reserva`, pl: `rezerwacja`, ipa: `/ʁɨˈzɛʁ.vɐ/`},{pt: `quarto`, pl: `pokój`, ipa: `/ˈkwaʁ.tu/`},{pt: `chave`, pl: `klucz`, ipa: `/ˈʃa.vɨ/`},{pt: `receção`, pl: `recepcja`, ipa: `/ʁɨ.sɨˈsɐ̃w/`},{pt: `documento`, pl: `dokument`, ipa: `/du.kuˈmẽ.tu/`},{pt: `noite`, pl: `noc`, ipa: `/ˈnoj.tɨ/`},{pt: `cama`, pl: `łóżko`, ipa: `/ˈka.mɐ/`},{pt: `pequeno-almoço`, pl: `śniadanie, Portugalia`, ipa: `/pɨˈke.nu aɫˈmo.su/`},{pt: `café da manhã`, pl: `śniadanie, Brazylia`, ipa: `/kaˈfɛ da maˈɲɐ̃/`}], phrases: [{pt: `Tenho uma reserva.`, pl: `Mam rezerwację.`, ipa: `/ˈte.ɲu ˈu.mɐ ʁɨˈzɛʁ.vɐ/`},{pt: `O meu nome é Kowalski.`, pl: `Nazywam się Kowalski.`, ipa: `/u mew ˈno.mɨ ɛ koˈvaɫ.ski/`},{pt: `Queria fazer o check-in.`, pl: `Chciałbym / chciałabym się zameldować.`, ipa: `/kɨˈɾi.ɐ fɐˈzeʁ u ˈtʃɛk in/`},{pt: `O pequeno-almoço está incluído?`, pl: `Czy śniadanie jest wliczone?`, ipa: `/u pɨˈke.nu aɫˈmo.su ʃˈta ĩ.kluˈi.du/`},{pt: `Qual é o número do quarto?`, pl: `Jaki jest numer pokoju?`, ipa: `/kwaɫ ɛ u ˈnu.mɨ.ɾu du ˈkwaʁ.tu/`},{pt: `Aqui está o meu documento.`, pl: `Oto mój dokument.`, ipa: `/ɐˈki ʃˈta u mew du.kuˈmẽ.tu/`}], grammar: `„Queria” dosłownie znaczy „chciałbym/chciałabym” i jest bardzo uprzejmą formą w hotelu, kawiarni czy sklepie. W Portugalii „receção” oznacza recepcję, a w Brazylii częściej spotkasz „recepção”. Różnice są małe, ale warto je rozpoznawać.`, practice: [`Powiedz recepcjoniście, że masz rezerwację.`,`Zapytaj o numer pokoju.`,`Zapytaj, czy śniadanie jest wliczone.`,`Podaj dokument w uprzejmy sposób.`,`Ułóż dialog: recepcja pyta o nazwisko, ty odpowiadasz.`]},{day: 8, title: `Kawiarnia i śniadanie`, title_native: `Café e pequeno-almoço`, focus: `Portugalia słynie z kawiarni, pastéis de nata i szybkiego espresso przy ladzie. Dziś nauczysz się zamawiać kawę, wodę i proste śniadanie.`, vocab: [{pt: `café`, pl: `kawa / espresso`, ipa: `/kɐˈfɛ/`},{pt: `galão`, pl: `kawa z mlekiem w wysokiej szklance`, ipa: `/ɡɐˈlɐ̃w/`},{pt: `chá`, pl: `herbata`, ipa: `/ʃa/`},{pt: `água`, pl: `woda`, ipa: `/ˈa.ɡwɐ/`},{pt: `sumo`, pl: `sok`, ipa: `/ˈsu.mu/`},{pt: `pão`, pl: `chleb`, ipa: `/pɐ̃w/`},{pt: `manteiga`, pl: `masło`, ipa: `/mɐ̃ˈtɐj.ɡɐ/`},{pt: `pastel de nata`, pl: `portugalska tartaletka z kremem`, ipa: `/pɐʃˈtɛɫ dɨ ˈna.tɐ/`},{pt: `açúcar`, pl: `cukier`, ipa: `/ɐˈsu.kaʁ/`},{pt: `leite`, pl: `mleko`, ipa: `/ˈlɐj.tɨ/`}], phrases: [{pt: `Queria um café, por favor.`, pl: `Poproszę kawę.`, ipa: `/kɨˈɾi.ɐ ũ kɐˈfɛ puʁ fɐˈvoʁ/`},{pt: `Uma água sem gás.`, pl: `Wodę niegazowaną.`, ipa: `/ˈu.mɐ ˈa.ɡwɐ sẽj ɡaʃ/`},{pt: `Uma água com gás.`, pl: `Wodę gazowaną.`, ipa: `/ˈu.mɐ ˈa.ɡwɐ kõ ɡaʃ/`},{pt: `Tem leite?`, pl: `Czy jest mleko?`, ipa: `/tẽj ˈlɐj.tɨ/`},{pt: `Sem açúcar, por favor.`, pl: `Bez cukru, proszę.`, ipa: `/sẽj ɐˈsu.kaʁ puʁ fɐˈvoʁ/`},{pt: `A conta, por favor.`, pl: `Rachunek, proszę.`, ipa: `/ɐ ˈkõ.tɐ puʁ fɐˈvoʁ/`}], grammar: `„Com” znaczy „z”, a „sem” znaczy „bez”. Te dwa słowa są bardzo praktyczne przy zamawianiu: „com leite”, „sem açúcar”, „sem gás”. W Portugalii „um café” zwykle oznacza małe espresso, nie dużą kawę filtrowaną.`, practice: [`Zamów kawę bez cukru.`,`Zamów wodę gazowaną.`,`Zapytaj, czy jest mleko.`,`Poproś o rachunek.`,`Wyobraź sobie śniadanie w kawiarni w Lizbonie i zamów trzy rzeczy.`]},{day: 9, title: `Jedzenie i restauracja`, title_native: `Comida e restaurante`, focus: `Nauczysz się rozumieć menu i zamawiać prosty posiłek w restauracji w Algarve lub w brazylijskim Belo Horizonte. Skupisz się na daniach, napojach i podstawowych preferencjach.`, vocab: [{pt: `restaurante`, pl: `restauracja`, ipa: `/ʁɨʃ.tɐwˈɾɐ̃.tɨ/`},{pt: `menu`, pl: `menu`, ipa: `/mɨˈnu/`},{pt: `prato`, pl: `danie / talerz`, ipa: `/ˈpɾa.tu/`},{pt: `entrada`, pl: `przystawka`, ipa: `/ẽˈtɾa.dɐ/`},{pt: `sopa`, pl: `zupa`, ipa: `/ˈso.pɐ/`},{pt: `peixe`, pl: `ryba`, ipa: `/ˈpɐj.ʃɨ/`},{pt: `carne`, pl: `mięso`, ipa: `/ˈkaʁ.nɨ/`},{pt: `frango`, pl: `kurczak`, ipa: `/ˈfɾɐ̃.ɡu/`},{pt: `arroz`, pl: `ryż`, ipa: `/ɐˈʁoʃ/`},{pt: `salada`, pl: `sałatka`, ipa: `/sɐˈla.dɐ/`}], phrases: [{pt: `Pode trazer o menu?`, pl: `Czy może pan / pani przynieść menu?`, ipa: `/ˈpɔ.dɨ tɾɐˈzeʁ u mɨˈnu/`},{pt: `Queria este prato.`, pl: `Poproszę to danie.`, ipa: `/kɨˈɾi.ɐ ˈeʃ.tɨ ˈpɾa.tu/`},{pt: `Sem carne, por favor.`, pl: `Bez mięsa, proszę.`, ipa: `/sẽj ˈkaʁ.nɨ puʁ fɐˈvoʁ/`},{pt: `Com arroz e salada.`, pl: `Z ryżem i sałatką.`, ipa: `/kõ ɐˈʁoʃ i sɐˈla.dɐ/`},{pt: `Está muito bom.`, pl: `To jest bardzo dobre.`, ipa: `/ʃˈta ˈmũj.tu bõ/`},{pt: `Mais uma água, por favor.`, pl: `Jeszcze jedną wodę, proszę.`, ipa: `/majʃ ˈu.mɐ ˈa.ɡwɐ puʁ fɐˈvoʁ/`}], grammar: `„Este” oznacza „ten” przy rzeczownikach męskich blisko nas, a „esta” przy żeńskich. W restauracji możesz wskazać na menu i powiedzieć „este prato”, nawet jeśli nie umiesz wymówić nazwy dania. „Mais uma” znaczy „jeszcze jedna”.`, practice: [`Poproś o menu.`,`Zamów danie, wskazując na kartę.`,`Powiedz „bez mięsa, proszę”.`,`Powiedz, że jedzenie jest bardzo dobre.`,`Poproś o jeszcze jedną wodę.`]},{day: 10, title: `Alergie i preferencje żywieniowe`, title_native: `Alergias e preferências alimentares`, focus: `Dziś nauczysz się bezpiecznie mówić o alergiach, diecie i składnikach. To ważne w restauracjach, piekarniach i na targach w krajach portugalskojęzycznych.`, vocab: [{pt: `alergia`, pl: `alergia`, ipa: `/ɐ.lɛʁˈʒi.ɐ/`},{pt: `amendoim`, pl: `orzech ziemny`, ipa: `/ɐ.mẽˈdoj̃/`},{pt: `nozes`, pl: `orzechy`, ipa: `/ˈnɔ.zɨʃ/`},{pt: `leite`, pl: `mleko`, ipa: `/ˈlɐj.tɨ/`},{pt: `glúten`, pl: `gluten`, ipa: `/ˈɡlu.tẽj/`},{pt: `ovo`, pl: `jajko`, ipa: `/ˈo.vu/`},{pt: `marisco`, pl: `owoce morza`, ipa: `/mɐˈɾiʃ.ku/`},{pt: `vegetariano`, pl: `wegetariański`, ipa: `/vɨ.ʒɨ.tɐˈɾjɐ.nu/`},{pt: `vegano`, pl: `wegański`, ipa: `/vɨˈɡa.nu/`},{pt: `ingrediente`, pl: `składnik`, ipa: `/ĩ.ɡɾɨ.diˈẽ.tɨ/`}], phrases: [{pt: `Tenho alergia a nozes.`, pl: `Mam alergię na orzechy.`, ipa: `/ˈte.ɲu ɐ.lɛʁˈʒi.ɐ ɐ ˈnɔ.zɨʃ/`},{pt: `Isto tem leite?`, pl: `Czy to ma mleko?`, ipa: `/ˈiʃ.tu tẽj ˈlɐj.tɨ/`},{pt: `Sou vegetariano.`, pl: `Jestem wegetarianinem.`, ipa: `/so vɨ.ʒɨ.tɐˈɾjɐ.nu/`},{pt: `Sou vegetariana.`, pl: `Jestem wegetarianką.`, ipa: `/so vɨ.ʒɨ.tɐˈɾjɐ.nɐ/`},{pt: `Sem glúten, por favor.`, pl: `Bez glutenu, proszę.`, ipa: `/sẽj ˈɡlu.tẽj puʁ fɐˈvoʁ/`},{pt: `Pode confirmar os ingredientes?`, pl: `Czy może pan / pani sprawdzić składniki?`, ipa: `/ˈpɔ.dɨ kõ.fiʁˈmaʁ uʒ ĩ.ɡɾɨ.diˈẽ.tɨʃ/`}], grammar: `Przymiotniki takie jak „vegetariano” i „vegetariana” dopasowują się do osoby mówiącej. Mężczyzna powie „sou vegetariano”, kobieta „sou vegetariana”. Przy alergiach używa się konstrukcji „Tenho alergia a…”, czyli „mam alergię na…”.`, practice: [`Powiedz, że masz alergię na orzechy.`,`Zapytaj, czy danie zawiera mleko.`,`Powiedz, że jesteś wegetarianinem albo wegetarianką.`,`Poproś o potwierdzenie składników.`,`Stwórz ostrzeżenie dla kelnera dotyczące glutenu.`]},{day: 11, title: `Kierunki i orientacja w mieście`, title_native: `Direções e orientação na cidade`, focus: `Wąskie uliczki Alfamy lub centrum Porto mogą być mylące. Dziś nauczysz się pytać o drogę i rozumieć proste wskazówki.`, vocab: [{pt: `rua`, pl: `ulica`, ipa: `/ˈʁu.ɐ/`},{pt: `praça`, pl: `plac`, ipa: `/ˈpɾa.sɐ/`},{pt: `centro`, pl: `centrum`, ipa: `/ˈsẽ.tɾu/`},{pt: `direita`, pl: `prawa strona`, ipa: `/diˈɾɐj.tɐ/`},{pt: `esquerda`, pl: `lewa strona`, ipa: `/ɨʃˈkeʁ.dɐ/`},{pt: `em frente`, pl: `prosto`, ipa: `/ẽ ˈfɾẽ.tɨ/`},{pt: `perto`, pl: `blisko`, ipa: `/ˈpɛʁ.tu/`},{pt: `longe`, pl: `daleko`, ipa: `/ˈlõ.ʒɨ/`},{pt: `ponte`, pl: `most`, ipa: `/ˈpõ.tɨ/`},{pt: `mapa`, pl: `mapa`, ipa: `/ˈma.pɐ/`}], phrases: [{pt: `Onde fica a estação?`, pl: `Gdzie jest stacja?`, ipa: `/ˈõ.dɨ ˈfi.kɐ ɐ ʃtɐˈsɐ̃w/`},{pt: `Vire à direita.`, pl: `Proszę skręcić w prawo.`, ipa: `/ˈvi.ɾɨ a diˈɾɐj.tɐ/`},{pt: `Vire à esquerda.`, pl: `Proszę skręcić w lewo.`, ipa: `/ˈvi.ɾɨ a ɨʃˈkeʁ.dɐ/`},{pt: `Siga em frente.`, pl: `Proszę iść prosto.`, ipa: `/ˈsi.ɡɐ ẽ ˈfɾẽ.tɨ/`},{pt: `É perto daqui?`, pl: `Czy to blisko stąd?`, ipa: `/ɛ ˈpɛʁ.tu dɐˈki/`},{pt: `Pode mostrar no mapa?`, pl: `Czy może pan / pani pokazać na mapie?`, ipa: `/ˈpɔ.dɨ muʃˈtɾaʁ nu ˈma.pɐ/`}], grammar: `Tryb rozkazujący w formach grzecznościowych często kończy się na „-e” lub „-a”, jak „vire” i „siga”. Nie musisz go aktywnie tworzyć na początku, ale warto rozumieć te słowa, gdy ktoś tłumaczy drogę. „Daqui” oznacza „stąd”.`, practice: [`Zapytaj, gdzie jest stacja.`,`Powiedz „proszę iść prosto”.`,`Zapytaj, czy miejsce jest blisko stąd.`,`Poproś, żeby ktoś pokazał drogę na mapie.`,`Przećwicz sekwencję: prosto, w lewo, w prawo.`]},{day: 12, title: `Transport publiczny`, title_native: `Transportes públicos`, focus: `Dziś nauczysz się kupować bilety i korzystać z metra, autobusu i pociągu. To praktyczne w Lizbonie, Porto, São Paulo i wielu innych miastach.`, vocab: [{pt: `metro`, pl: `metro`, ipa: `/ˈmɛ.tɾu/`},{pt: `autocarro`, pl: `autobus, Portugalia`, ipa: `/aw.tuˈka.ʁu/`},{pt: `ônibus`, pl: `autobus, Brazylia`, ipa: `/ˈõ.ni.bus/`},{pt: `comboio`, pl: `pociąg, Portugalia`, ipa: `/kõˈboj.u/`},{pt: `trem`, pl: `pociąg, Brazylia`, ipa: `/tɾẽj/`},{pt: `bilhete`, pl: `bilet`, ipa: `/biˈʎe.tɨ/`},{pt: `cartão`, pl: `karta`, ipa: `/kɐʁˈtɐ̃w/`},{pt: `estação`, pl: `stacja`, ipa: `/ʃtɐˈsɐ̃w/`},{pt: `paragem`, pl: `przystanek`, ipa: `/pɐˈɾa.ʒɐ̃j/`},{pt: `linha`, pl: `linia`, ipa: `/ˈli.ɲɐ/`}], phrases: [{pt: `Queria um bilhete para o centro.`, pl: `Poproszę bilet do centrum.`, ipa: `/kɨˈɾi.ɐ ũ biˈʎe.tɨ pɐɾɐ u ˈsẽ.tɾu/`},{pt: `Qual é a linha certa?`, pl: `Która linia jest właściwa?`, ipa: `/kwaɫ ɛ ɐ ˈli.ɲɐ ˈsɛʁ.tɐ/`},{pt: `Este autocarro vai para Belém?`, pl: `Czy ten autobus jedzie do Belém?`, ipa: `/ˈeʃ.tɨ aw.tuˈka.ʁu vaj pɐɾɐ bɨˈlẽj/`},{pt: `Onde compro o cartão?`, pl: `Gdzie kupię kartę?`, ipa: `/ˈõ.dɨ ˈkõ.pɾu u kɐʁˈtɐ̃w/`},{pt: `A próxima paragem é esta?`, pl: `Czy następny przystanek to ten?`, ipa: `/ɐ ˈpɾɔ.si.mɐ pɐˈɾa.ʒɐ̃j ɛ ˈeʃ.tɐ/`},{pt: `A que horas sai o comboio?`, pl: `O której odjeżdża pociąg?`, ipa: `/ɐ kɨ ˈɔ.ɾɐʃ saj u kõˈboj.u/`}], grammar: `„Para” oznacza „do” lub „w kierunku”, bardzo przydatne w transporcie. „Vai para…” znaczy „jedzie do…”. Pamiętaj o różnicach regionalnych: Portugalia mówi „autocarro” i „comboio”, Brazylia częściej „ônibus” i „trem”.`, practice: [`Kup bilet do centrum.`,`Zapytaj, która linia jest właściwa.`,`Zapytaj, czy autobus jedzie do wybranego miejsca.`,`Zapytaj, gdzie kupić kartę miejską.`,`Powiedz „o której odjeżdża pociąg?”.`]},{day: 13, title: `Taksówka i przejazd`, title_native: `Táxi e viagem`, focus: `Przyda Ci się to po późnym przylocie, z ciężkim bagażem albo w mieście bez łatwego metra. Nauczysz się podawać adres, pytać o cenę i prosić o zatrzymanie.`, vocab: [{pt: `táxi`, pl: `taksówka`, ipa: `/ˈta.ksi/`},{pt: `motorista`, pl: `kierowca`, ipa: `/mu.tuˈɾiʃ.tɐ/`},{pt: `endereço`, pl: `adres`, ipa: `/ẽ.dɨˈɾe.su/`},{pt: `aqui`, pl: `tutaj`, ipa: `/ɐˈki/`},{pt: `ali`, pl: `tam`, ipa: `/ɐˈli/`},{pt: `rápido`, pl: `szybko`, ipa: `/ˈʁa.pi.du/`},{pt: `devagar`, pl: `powoli`, ipa: `/dɨ.vɐˈɡaʁ/`},{pt: `preço`, pl: `cena`, ipa: `/ˈpɾe.su/`},{pt: `aplicação`, pl: `aplikacja`, ipa: `/ɐ.pli.kɐˈsɐ̃w/`},{pt: `parar`, pl: `zatrzymać się`, ipa: `/pɐˈɾaʁ/`}], phrases: [{pt: `Pode levar-me a este endereço?`, pl: `Czy może mnie pan / pani zawieźć pod ten adres?`, ipa: `/ˈpɔ.dɨ lɨˈvaʁ mɨ a ˈeʃ.tɨ ẽ.dɨˈɾe.su/`},{pt: `Quanto custa até ao hotel?`, pl: `Ile kosztuje do hotelu?`, ipa: `/ˈkwɐ̃.tu ˈkuʃ.tɐ ɐˈtɛ aw oˈtɛɫ/`},{pt: `Pode parar aqui?`, pl: `Czy może pan / pani zatrzymać się tutaj?`, ipa: `/ˈpɔ.dɨ pɐˈɾaʁ ɐˈki/`},{pt: `Mais devagar, por favor.`, pl: `Wolniej, proszę.`, ipa: `/majʃ dɨ.vɐˈɡaʁ puʁ fɐˈvoʁ/`},{pt: `Tenho bagagem.`, pl: `Mam bagaż.`, ipa: `/ˈte.ɲu bɐˈɡa.ʒɐ̃j/`},{pt: `Pago com cartão.`, pl: `Płacę kartą.`, ipa: `/ˈpa.ɡu kõ kɐʁˈtɐ̃w/`}], grammar: `W portugalskim „pagar com cartão” oznacza płacić kartą, a „pagar em dinheiro” płacić gotówką. „Pode…?” to bardzo użyteczny sposób proszenia: „Pode parar?”, „Pode levar-me?”. W Brazylii częściej usłyszysz „me levar” zamiast portugalskiego „levar-me”.`, practice: [`Poproś kierowcę o kurs pod adres.`,`Zapytaj o cenę do hotelu.`,`Poproś o zatrzymanie tutaj.`,`Powiedz, że płacisz kartą.`,`Wyobraź sobie przejazd z lotniska i podaj dwie ważne informacje kierowcy.`]},{day: 14, title: `Zakupy i ceny`, title_native: `Compras e preços`, focus: `Na targu w Lizbonie, w sklepie z pamiątkami w Porto lub na rynku w Brazylii trzeba pytać o ceny i rozmiary. Dziś nauczysz się kupować proste rzeczy.`, vocab: [{pt: `loja`, pl: `sklep`, ipa: `/ˈlɔ.ʒɐ/`},{pt: `mercado`, pl: `targ / rynek`, ipa: `/mɨʁˈka.du/`},{pt: `preço`, pl: `cena`, ipa: `/ˈpɾe.su/`},{pt: `caro`, pl: `drogi`, ipa: `/ˈka.ɾu/`},{pt: `barato`, pl: `tani`, ipa: `/bɐˈɾa.tu/`},{pt: `dinheiro`, pl: `pieniądze / gotówka`, ipa: `/diˈɲɐj.ɾu/`},{pt: `cartão`, pl: `karta`, ipa: `/kɐʁˈtɐ̃w/`},{pt: `recibo`, pl: `paragon`, ipa: `/ʁɨˈsi.bu/`},{pt: `saco`, pl: `torba`, ipa: `/ˈsa.ku/`},{pt: `tamanho`, pl: `rozmiar`, ipa: `/tɐˈma.ɲu/`}], phrases: [{pt: `Quanto custa isto?`, pl: `Ile to kosztuje?`, ipa: `/ˈkwɐ̃.tu ˈkuʃ.tɐ ˈiʃ.tu/`},{pt: `Tem outro tamanho?`, pl: `Czy jest inny rozmiar?`, ipa: `/tẽj ˈo.tɾu tɐˈma.ɲu/`},{pt: `É muito caro.`, pl: `To jest bardzo drogie.`, ipa: `/ɛ ˈmũj.tu ˈka.ɾu/`},{pt: `Pago em dinheiro.`, pl: `Płacę gotówką.`, ipa: `/ˈpa.ɡu ẽ diˈɲɐj.ɾu/`},{pt: `Pode dar-me um recibo?`, pl: `Czy może pan / pani dać mi paragon?`, ipa: `/ˈpɔ.dɨ daʁ mɨ ũ ʁɨˈsi.bu/`},{pt: `Preciso de um saco.`, pl: `Potrzebuję torby.`, ipa: `/pɾɨˈsi.zu dɨ ũ ˈsa.ku/`}], grammar: `„Isto” oznacza „to” i jest świetne, gdy wskazujesz przedmiot. „Outro” znaczy „inny” przy rzeczowniku męskim, a „outra” przy żeńskim. Możesz powiedzieć „outro tamanho” albo „outra cor”.`, practice: [`Zapytaj o cenę wskazanego przedmiotu.`,`Powiedz, że coś jest bardzo drogie.`,`Zapytaj o inny rozmiar.`,`Poproś o paragon.`,`Powiedz, że płacisz gotówką.`]},{day: 15, title: `Kolory i ubrania`, title_native: `Cores e roupas`, focus: `Dziś rozwiniesz język zakupów o kolory i ubrania. Przyda się to w centrum handlowym w Lizbonie albo w małym sklepie w Funchal na Maderze.`, vocab: [{pt: `roupa`, pl: `ubranie`, ipa: `/ˈʁo.pɐ/`},{pt: `camisa`, pl: `koszula`, ipa: `/kɐˈmi.zɐ/`},{pt: `camiseta`, pl: `koszulka, Brazylia`, ipa: `/ka.miˈze.tɐ/`},{pt: `calças`, pl: `spodnie`, ipa: `/ˈkaɫ.sɐʃ/`},{pt: `sapatos`, pl: `buty`, ipa: `/sɐˈpa.tuʃ/`},{pt: `vermelho`, pl: `czerwony`, ipa: `/vɨʁˈme.ʎu/`},{pt: `azul`, pl: `niebieski`, ipa: `/ɐˈzuɫ/`},{pt: `branco`, pl: `biały`, ipa: `/ˈbɾɐ̃.ku/`},{pt: `preto`, pl: `czarny`, ipa: `/ˈpɾe.tu/`},{pt: `verde`, pl: `zielony`, ipa: `/ˈveʁ.dɨ/`}], phrases: [{pt: `Tem esta camisa em azul?`, pl: `Czy jest ta koszula w kolorze niebieskim?`, ipa: `/tẽj ˈeʃ.tɐ kɐˈmi.zɐ ẽ ɐˈzuɫ/`},{pt: `Queria experimentar.`, pl: `Chciałbym / chciałabym przymierzyć.`, ipa: `/kɨˈɾi.ɐ eʃ.pɨ.ɾi.mẽˈtaʁ/`},{pt: `Onde é o provador?`, pl: `Gdzie jest przymierzalnia?`, ipa: `/ˈõ.dɨ ɛ u pɾu.vɐˈdoʁ/`},{pt: `Fica bem.`, pl: `Pasuje dobrze.`, ipa: `/ˈfi.kɐ bẽj/`},{pt: `É pequeno demais.`, pl: `Jest za małe.`, ipa: `/ɛ pɨˈke.nu dɨˈmajʃ/`},{pt: `É grande demais.`, pl: `Jest za duże.`, ipa: `/ɛ ˈɡɾɐ̃.dɨ dɨˈmajʃ/`}], grammar: `Kolory są przymiotnikami i często dopasowują się do rodzaju oraz liczby: „camisa branca”, „sapatos pretos”. Niektóre kolory, jak „azul” i „verde”, mają tę samą formę dla rodzaju męskiego i żeńskiego. „Demais” po przymiotniku znaczy „za bardzo”, czyli „za duży” lub „za mały”.`, practice: [`Zapytaj o niebieską koszulę.`,`Poproś o możliwość przymierzenia.`,`Zapytaj, gdzie jest przymierzalnia.`,`Powiedz, że coś jest za małe.`,`Opisz po portugalsku dwa kolory ubrań, które masz dziś na sobie.`]},{day: 16, title: `Dni, godziny i plany`, title_native: `Dias, horas e planos`, focus: `Nauczysz się mówić o dniach tygodnia i godzinach. To pomoże przy rezerwacjach, wycieczkach, muzeach i spotkaniach w portugalskojęzycznym mieście.`, vocab: [{pt: `hoje`, pl: `dzisiaj`, ipa: `/ˈo.ʒɨ/`},{pt: `amanhã`, pl: `jutro`, ipa: `/ɐ.mɐˈɲɐ̃/`},{pt: `ontem`, pl: `wczoraj`, ipa: `/ˈõ.tẽj/`},{pt: `segunda-feira`, pl: `poniedziałek`, ipa: `/sɨˈɡũ.dɐ ˈfɐj.ɾɐ/`},{pt: `terça-feira`, pl: `wtorek`, ipa: `/ˈtɛʁ.sɐ ˈfɐj.ɾɐ/`},{pt: `quarta-feira`, pl: `środa`, ipa: `/ˈkwaʁ.tɐ ˈfɐj.ɾɐ/`},{pt: `sexta-feira`, pl: `piątek`, ipa: `/ˈseʃ.tɐ ˈfɐj.ɾɐ/`},{pt: `hora`, pl: `godzina`, ipa: `/ˈɔ.ɾɐ/`},{pt: `meia-noite`, pl: `północ`, ipa: `/ˈmɐj.ɐ ˈnoj.tɨ/`},{pt: `meio-dia`, pl: `południe`, ipa: `/ˈmɐj.u ˈdi.ɐ/`}], phrases: [{pt: `Que horas são?`, pl: `Która godzina?`, ipa: `/kɨ ˈɔ.ɾɐʃ sɐ̃w/`},{pt: `São três horas.`, pl: `Jest trzecia.`, ipa: `/sɐ̃w tɾeʃ ˈɔ.ɾɐʃ/`},{pt: `A que horas abre?`, pl: `O której się otwiera?`, ipa: `/ɐ kɨ ˈɔ.ɾɐʃ ˈa.bɾɨ/`},{pt: `A que horas fecha?`, pl: `O której się zamyka?`, ipa: `/ɐ kɨ ˈɔ.ɾɐʃ ˈfe.ʃɐ/`},{pt: `Tenho uma reserva amanhã.`, pl: `Mam rezerwację jutro.`, ipa: `/ˈte.ɲu ˈu.mɐ ʁɨˈzɛʁ.vɐ ɐ.mɐˈɲɐ̃/`},{pt: `Hoje à noite.`, pl: `Dziś wieczorem.`, ipa: `/ˈo.ʒɨ a ˈnoj.tɨ/`}], grammar: `Dni tygodnia w portugalskim od poniedziałku do piątku kończą się na „-feira”. Przy godzinach używa się „são” dla większości godzin, ale „é uma hora” dla pierwszej. „À noite” oznacza „wieczorem” lub „w nocy”, zależnie od kontekstu.`, practice: [`Zapytaj, która godzina.`,`Powiedz „jest trzecia”.`,`Zapytaj, o której otwiera się muzeum.`,`Powiedz, że masz rezerwację jutro.`,`Zaplanuj krótko: dzisiaj wieczorem, jutro rano, w piątek.`]},{day: 17, title: `Pogoda i ubranie na dzień`, title_native: `Tempo e roupa para o dia`, focus: `Pogoda w Portugalii może szybko zmienić się między wybrzeżem a wzgórzami, a w Brazylii zależy od regionu. Dziś nauczysz się mówić o słońcu, deszczu i temperaturze.`, vocab: [{pt: `tempo`, pl: `pogoda / czas`, ipa: `/ˈtẽ.pu/`},{pt: `sol`, pl: `słońce`, ipa: `/sɔɫ/`},{pt: `chuva`, pl: `deszcz`, ipa: `/ˈʃu.vɐ/`},{pt: `vento`, pl: `wiatr`, ipa: `/ˈvẽ.tu/`},{pt: `calor`, pl: `upał / ciepło`, ipa: `/kɐˈloʁ/`},{pt: `frio`, pl: `zimno`, ipa: `/ˈfɾi.u/`},{pt: `nublado`, pl: `pochmurnie`, ipa: `/nuˈbla.du/`},{pt: `casaco`, pl: `kurtka`, ipa: `/kɐˈza.ku/`},{pt: `guarda-chuva`, pl: `parasol`, ipa: `/ˈɡwaʁ.dɐ ˈʃu.vɐ/`},{pt: `temperatura`, pl: `temperatura`, ipa: `/tẽ.pɨ.ɾɐˈtu.ɾɐ/`}], phrases: [{pt: `Está sol.`, pl: `Jest słonecznie.`, ipa: `/ʃˈta sɔɫ/`},{pt: `Está a chover.`, pl: `Pada deszcz, Portugalia.`, ipa: `/ʃˈta ɐ ʃuˈveʁ/`},{pt: `Está chovendo.`, pl: `Pada deszcz, Brazylia.`, ipa: `/esˈta ʃoˈvẽ.du/`},{pt: `Está frio hoje.`, pl: `Dzisiaj jest zimno.`, ipa: `/ʃˈta ˈfɾi.u ˈo.ʒɨ/`},{pt: `Preciso de um casaco.`, pl: `Potrzebuję kurtki.`, ipa: `/pɾɨˈsi.zu dɨ ũ kɐˈza.ku/`},{pt: `Tem guarda-chuva?`, pl: `Czy jest parasol?`, ipa: `/tẽj ˈɡwaʁ.dɐ ˈʃu.vɐ/`}], grammar: `W Portugalii do opisu pogody często używa się „está”: „Está frio”, „Está sol”. Konstrukcja trwająca różni się regionalnie: Portugalia mówi „está a chover”, Brazylia „está chovendo”. Obie formy znaczą „pada”.`, practice: [`Powiedz, że jest słonecznie.`,`Powiedz, że dziś jest zimno.`,`Zapytaj, czy jest parasol.`,`Powiedz, że potrzebujesz kurtki.`,`Opisz pogodę w swoim mieście trzema prostymi zdaniami po portugalsku.`]},{day: 18, title: `Telefon, internet i technologia`, title_native: `Telemóvel, internet e tecnologia`, focus: `Dziś nauczysz się pytać o Wi-Fi, ładowarkę, kartę SIM i zasięg. Przyda się to w hotelu, kawiarni lub sklepie telefonicznym.`, vocab: [{pt: `telemóvel`, pl: `telefon komórkowy, Portugalia`, ipa: `/tɨ.lɨˈmɔ.vɨɫ/`},{pt: `celular`, pl: `telefon komórkowy, Brazylia`, ipa: `/se.luˈlaʁ/`},{pt: `internet`, pl: `internet`, ipa: `/ĩ.tɨʁˈnɛt/`},{pt: `Wi-Fi`, pl: `Wi-Fi`, ipa: `/waj faj/`},{pt: `senha`, pl: `hasło, Brazylia`, ipa: `/ˈse.ɲɐ/`},{pt: `palavra-passe`, pl: `hasło, Portugalia`, ipa: `/pɐˈlavɾɐ ˈpa.sɨ/`},{pt: `carregador`, pl: `ładowarka`, ipa: `/kɐ.ʁɨ.ɡɐˈdoʁ/`},{pt: `tomada`, pl: `gniazdko`, ipa: `/tuˈma.dɐ/`},{pt: `cartão SIM`, pl: `karta SIM`, ipa: `/kɐʁˈtɐ̃w sim/`},{pt: `rede`, pl: `sieć / zasięg`, ipa: `/ˈʁe.dɨ/`}], phrases: [{pt: `Qual é a palavra-passe do Wi-Fi?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `/kwaɫ ɛ ɐ pɐˈlavɾɐ ˈpa.sɨ du waj faj/`},{pt: `Tem internet aqui?`, pl: `Czy jest tutaj internet?`, ipa: `/tẽj ĩ.tɨʁˈnɛt ɐˈki/`},{pt: `Preciso de um carregador.`, pl: `Potrzebuję ładowarki.`, ipa: `/pɾɨˈsi.zu dɨ ũ kɐ.ʁɨ.ɡɐˈdoʁ/`},{pt: `Onde há uma tomada?`, pl: `Gdzie jest gniazdko?`, ipa: `/ˈõ.dɨ a ˈu.mɐ tuˈma.dɐ/`},{pt: `Queria comprar um cartão SIM.`, pl: `Chciałbym / chciałabym kupić kartę SIM.`, ipa: `/kɨˈɾi.ɐ kõˈpɾaʁ ũ kɐʁˈtɐ̃w sim/`},{pt: `Não tenho rede.`, pl: `Nie mam zasięgu.`, ipa: `/nɐ̃w ˈte.ɲu ˈʁe.dɨ/`}], grammar: `„Há” oznacza „jest” lub „są” w sensie istnienia czegoś, na przykład „Há uma tomada?” czyli „Czy jest gniazdko?”. „Tenho” mówi o posiadaniu: „Tenho internet”, „Não tenho rede”. W Portugalii hasło to „palavra-passe”, w Brazylii „senha”.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że potrzebujesz ładowarki.`,`Zapytaj, gdzie jest gniazdko.`,`Powiedz, że nie masz zasięgu.`,`Poproś w sklepie o kartę SIM.`]},{day: 19, title: `Apteka i zdrowie`, title_native: `Farmácia e saúde`, focus: `Dziś przygotujesz się do wizyty w aptece w Portugalii lub Brazylii. Nauczysz się opisać podstawowy problem zdrowotny i poprosić o pomoc.`, vocab: [{pt: `farmácia`, pl: `apteka`, ipa: `/fɐʁˈma.sjɐ/`},{pt: `dor`, pl: `ból`, ipa: `/doʁ/`},{pt: `cabeça`, pl: `głowa`, ipa: `/kɐˈbe.sɐ/`},{pt: `estômago`, pl: `żołądek`, ipa: `/ɨʃˈtɔ.mɐ.ɡu/`},{pt: `garganta`, pl: `gardło`, ipa: `/ɡɐʁˈɡɐ̃.tɐ/`},{pt: `febre`, pl: `gorączka`, ipa: `/ˈfɛ.bɾɨ/`},{pt: `remédio`, pl: `lekarstwo`, ipa: `/ʁɨˈmɛ.djʊ/`},{pt: `médico`, pl: `lekarz`, ipa: `/ˈmɛ.di.ku/`},{pt: `hospital`, pl: `szpital`, ipa: `/uʃ.piˈtaɫ/`},{pt: `ajuda`, pl: `pomoc`, ipa: `/ɐjˈu.dɐ/`}], phrases: [{pt: `Tenho dor de cabeça.`, pl: `Boli mnie głowa.`, ipa: `/ˈte.ɲu doʁ dɨ kɐˈbe.sɐ/`},{pt: `Tenho dor de estômago.`, pl: `Boli mnie żołądek.`, ipa: `/ˈte.ɲu doʁ dɨ ɨʃˈtɔ.mɐ.ɡu/`},{pt: `Tenho febre.`, pl: `Mam gorączkę.`, ipa: `/ˈte.ɲu ˈfɛ.bɾɨ/`},{pt: `Preciso de um remédio.`, pl: `Potrzebuję lekarstwa.`, ipa: `/pɾɨˈsi.zu dɨ ũ ʁɨˈmɛ.djʊ/`},{pt: `Há uma farmácia perto?`, pl: `Czy jest apteka w pobliżu?`, ipa: `/a ˈu.mɐ fɐʁˈma.sjɐ ˈpɛʁ.tu/`},{pt: `Preciso de um médico.`, pl: `Potrzebuję lekarza.`, ipa: `/pɾɨˈsi.zu dɨ ũ ˈmɛ.di.ku/`}], grammar: `Aby powiedzieć, że coś Cię boli, używasz „Tenho dor de…”, dosłownie „mam ból…”. To proste i bardzo przydatne: „Tenho dor de garganta”, „Tenho dor de cabeça”. „Preciso de” działa także z osobami i usługami, jak „um médico” lub „ajuda”.`, practice: [`Powiedz, że boli Cię głowa.`,`Powiedz, że masz gorączkę.`,`Zapytaj, czy apteka jest w pobliżu.`,`Powiedz, że potrzebujesz lekarstwa.`,`Przygotuj trzy zdania do farmaceuty.`]},{day: 20, title: `Nagłe sytuacje`, title_native: `Emergências`, focus: `Dziś nauczysz się słów i zwrotów potrzebnych w sytuacjach awaryjnych. To materiał, który warto znać nawet, jeśli użyjesz go bardzo rzadko.`, vocab: [{pt: `emergência`, pl: `nagły wypadek`, ipa: `/i.mɨʁˈʒẽ.sjɐ/`},{pt: `polícia`, pl: `policja`, ipa: `/puˈli.sjɐ/`},{pt: `ambulância`, pl: `karetka`, ipa: `/ɐ̃.buˈlɐ̃.sjɐ/`},{pt: `fogo`, pl: `ogień`, ipa: `/ˈfo.ɡu/`},{pt: `perigo`, pl: `niebezpieczeństwo`, ipa: `/pɨˈɾi.ɡu/`},{pt: `roubo`, pl: `kradzież`, ipa: `/ˈʁo.bu/`},{pt: `perdido`, pl: `zgubiony, męskie`, ipa: `/pɨʁˈdi.du/`},{pt: `perdida`, pl: `zgubiona, żeńskie`, ipa: `/pɨʁˈdi.dɐ/`},{pt: `socorro`, pl: `ratunku`, ipa: `/suˈko.ʁu/`},{pt: `seguro`, pl: `bezpieczny`, ipa: `/sɨˈɡu.ɾu/`}], phrases: [{pt: `Ajuda, por favor!`, pl: `Pomocy, proszę!`, ipa: `/ɐjˈu.dɐ puʁ fɐˈvoʁ/`},{pt: `Chame a polícia.`, pl: `Proszę wezwać policję.`, ipa: `/ˈʃa.mɨ ɐ puˈli.sjɐ/`},{pt: `Chame uma ambulância.`, pl: `Proszę wezwać karetkę.`, ipa: `/ˈʃa.mɨ ˈu.mɐ ɐ̃.buˈlɐ̃.sjɐ/`},{pt: `Perdi o meu passaporte.`, pl: `Zgubiłem / zgubiłam mój paszport.`, ipa: `/ˈpɛʁ.di u mew pɐ.sɐˈpɔʁ.tɨ/`},{pt: `Fui roubado.`, pl: `Zostałem okradziony.`, ipa: `/fuj ʁoˈba.du/`},{pt: `Fui roubada.`, pl: `Zostałam okradziona.`, ipa: `/fuj ʁoˈba.dɐ/`}], grammar: `W nagłych sytuacjach krótkie zdania są najlepsze. „Chame…” to grzeczna, ale stanowcza forma „proszę wezwać…”. Formy „roubado” i „roubada” dopasowują się do osoby mówiącej, podobnie jak „obrigado/obrigada”.`, practice: [`Powiedz „pomocy, proszę!”.`,`Poproś o wezwanie policji.`,`Poproś o wezwanie karetki.`,`Powiedz, że zgubiłeś / zgubiłaś paszport.`,`Przećwicz spokojne zgłoszenie kradzieży w dwóch zdaniach.`]},{day: 21, title: `Zwiedzanie i atrakcje`, title_native: `Turismo e atrações`, focus: `Dziś nauczysz się mówić o muzeach, biletach, widokach i godzinach otwarcia. Przyda się to podczas zwiedzania Belém, Sintry lub historycznego centrum Salvadoru.`, vocab: [{pt: `museu`, pl: `muzeum`, ipa: `/muˈzew/`},{pt: `igreja`, pl: `kościół`, ipa: `/iˈɡɾe.ʒɐ/`},{pt: `castelo`, pl: `zamek`, ipa: `/kɐʃˈtɛ.lu/`},{pt: `praia`, pl: `plaża`, ipa: `/ˈpɾaj.ɐ/`},{pt: `vista`, pl: `widok`, ipa: `/ˈviʃ.tɐ/`},{pt: `bilheteira`, pl: `kasa biletowa`, ipa: `/bi.ʎɨˈtɐj.ɾɐ/`},{pt: `entrada`, pl: `wejście / bilet wstępu`, ipa: `/ẽˈtɾa.dɐ/`},{pt: `guia`, pl: `przewodnik`, ipa: `/ˈɡi.ɐ/`},{pt: `excursão`, pl: `wycieczka`, ipa: `/ɨʃ.kuʁˈsɐ̃w/`},{pt: `fotografia`, pl: `fotografia`, ipa: `/fu.tu.ɡɾɐˈfi.ɐ/`}], phrases: [{pt: `Onde é a entrada?`, pl: `Gdzie jest wejście?`, ipa: `/ˈõ.dɨ ɛ ɐ ẽˈtɾa.dɐ/`},{pt: `Quanto custa a entrada?`, pl: `Ile kosztuje wejście?`, ipa: `/ˈkwɐ̃.tu ˈkuʃ.tɐ ɐ ẽˈtɾa.dɐ/`},{pt: `Posso tirar fotografias?`, pl: `Czy mogę robić zdjęcia?`, ipa: `/ˈpɔ.su tiˈɾaʁ fu.tu.ɡɾɐˈfi.ɐʃ/`},{pt: `Há uma visita guiada?`, pl: `Czy jest zwiedzanie z przewodnikiem?`, ipa: `/a ˈu.mɐ viˈzi.tɐ ɡiˈa.dɐ/`},{pt: `A vista é linda.`, pl: `Widok jest piękny.`, ipa: `/ɐ ˈviʃ.tɐ ɛ ˈlĩ.dɐ/`},{pt: `Queria dois bilhetes.`, pl: `Poproszę dwa bilety.`, ipa: `/kɨˈɾi.ɐ dojʃ biˈʎe.tɨʃ/`}], grammar: `„Posso…” znaczy „czy mogę…” i jest bardzo praktyczne przy pytaniu o pozwolenie. „Há…” oznacza „czy jest/są…”, więc „Há uma visita guiada?” to proste pytanie o dostępność. Warto zapamiętać „entrada”, bo może oznaczać zarówno wejście, jak i bilet wstępu.`, practice: [`Zapytaj, gdzie jest wejście.`,`Zapytaj, ile kosztuje bilet wstępu.`,`Zapytaj, czy można robić zdjęcia.`,`Poproś o dwa bilety.`,`Powiedz, że widok jest piękny.`]},{day: 22, title: `Plaża i czas wolny`, title_native: `Praia e tempo livre`, focus: `Portugalia, Brazylia, Angola i Mozambik mają wiele nadmorskich miejsc. Dziś nauczysz się słów potrzebnych na plaży i przy planowaniu wolnego czasu.`, vocab: [{pt: `praia`, pl: `plaża`, ipa: `/ˈpɾaj.ɐ/`},{pt: `mar`, pl: `morze`, ipa: `/maʁ/`},{pt: `areia`, pl: `piasek`, ipa: `/ɐˈɾɐj.ɐ/`},{pt: `sol`, pl: `słońce`, ipa: `/sɔɫ/`},{pt: `protetor solar`, pl: `krem z filtrem`, ipa: `/pɾu.tɨˈtoʁ suˈlaʁ/`},{pt: `toalha`, pl: `ręcznik`, ipa: `/tuˈa.ʎɐ/`},{pt: `água do mar`, pl: `woda morska`, ipa: `/ˈa.ɡwɐ du maʁ/`},{pt: `nadar`, pl: `pływać`, ipa: `/nɐˈdaʁ/`},{pt: `descansar`, pl: `odpoczywać`, ipa: `/dɨʃ.kɐ̃ˈsaʁ/`},{pt: `pôr do sol`, pl: `zachód słońca`, ipa: `/poʁ du sɔɫ/`}], phrases: [{pt: `Vamos à praia?`, pl: `Idziemy na plażę?`, ipa: `/ˈva.muʃ a ˈpɾaj.ɐ/`},{pt: `Preciso de protetor solar.`, pl: `Potrzebuję kremu z filtrem.`, ipa: `/pɾɨˈsi.zu dɨ pɾu.tɨˈtoʁ suˈlaʁ/`},{pt: `A água está fria.`, pl: `Woda jest zimna.`, ipa: `/ɐ ˈa.ɡwɐ ʃˈta ˈfɾi.ɐ/`},{pt: `Gosto de nadar.`, pl: `Lubię pływać.`, ipa: `/ˈɡɔʃ.tu dɨ nɐˈdaʁ/`},{pt: `Quero descansar.`, pl: `Chcę odpocząć.`, ipa: `/ˈkɛ.ɾu dɨʃ.kɐ̃ˈsaʁ/`},{pt: `O pôr do sol é bonito.`, pl: `Zachód słońca jest piękny.`, ipa: `/u poʁ du sɔɫ ɛ buˈni.tu/`}], grammar: `„Gosto de…” oznacza „lubię…” i łączy się z bezokolicznikiem: „Gosto de nadar”, „Gosto de caminhar”. „Quero…” znaczy „chcę…” i też może łączyć się z czasownikiem: „Quero descansar”. To bardzo proste konstrukcje do rozmowy o planach.`, practice: [`Zaproponuj wyjście na plażę.`,`Powiedz, że potrzebujesz kremu z filtrem.`,`Powiedz, że woda jest zimna.`,`Powiedz, że lubisz pływać.`,`Opisz idealne popołudnie na plaży w trzech prostych zdaniach.`]},{day: 23, title: `Rozmowa towarzyska`, title_native: `Conversa social`, focus: `Dziś nauczysz się prowadzić krótką, uprzejmą rozmowę z lokalną osobą. Przyda się to w barze, na wycieczce albo podczas czekania w kolejce.`, vocab: [{pt: `amigo`, pl: `przyjaciel`, ipa: `/ɐˈmi.ɡu/`},{pt: `amiga`, pl: `przyjaciółka`, ipa: `/ɐˈmi.ɡɐ/`},{pt: `cidade`, pl: `miasto`, ipa: `/siˈda.dɨ/`},{pt: `país`, pl: `kraj`, ipa: `/pɐˈiʃ/`},{pt: `viagem`, pl: `podróż`, ipa: `/viˈa.ʒɐ̃j/`},{pt: `trabalho`, pl: `praca`, ipa: `/tɾɐˈba.ʎu/`},{pt: `férias`, pl: `wakacje`, ipa: `/ˈfɛ.ɾjɐʃ/`},{pt: `música`, pl: `muzyka`, ipa: `/ˈmu.zi.kɐ/`},{pt: `família`, pl: `rodzina`, ipa: `/fɐˈmi.ljɐ/`},{pt: `legal`, pl: `fajny, Brazylia`, ipa: `/leˈɡaw/`}], phrases: [{pt: `De onde é?`, pl: `Skąd pan / pani jest?`, ipa: `/dɨ ˈõ.dɨ ɛ/`},{pt: `Sou da Polónia.`, pl: `Jestem z Polski.`, ipa: `/so dɐ puˈlɔ.njɐ/`},{pt: `Gosta de Portugal?`, pl: `Czy podoba się panu / pani Portugalia?`, ipa: `/ˈɡɔʃ.tɐ dɨ puʁtuˈɡaɫ/`},{pt: `Gosto muito daqui.`, pl: `Bardzo mi się tutaj podoba.`, ipa: `/ˈɡɔʃ.tu ˈmũj.tu dɐˈki/`},{pt: `Estou de férias.`, pl: `Jestem na wakacjach.`, ipa: `/ʃˈtow dɨ ˈfɛ.ɾjɐʃ/`},{pt: `A cidade é bonita.`, pl: `Miasto jest piękne.`, ipa: `/ɐ siˈda.dɨ ɛ buˈni.tɐ/`}], grammar: `„Gostar de” dosłownie działa jak „lubić coś”, ale w pytaniu „Gosta de Portugal?” oznacza też „Czy podoba się panu/pani Portugalia?”. „Estou de férias” to stały zwrot oznaczający „jestem na wakacjach”. „Daqui” znaczy „stąd” lub „tutaj”, zależnie od zdania.`, practice: [`Zapytaj kogoś, skąd jest.`,`Powiedz, że jesteś z Polski.`,`Powiedz, że jesteś na wakacjach.`,`Powiedz, że bardzo podoba Ci się tutaj.`,`Ułóż krótką rozmowę z lokalną osobą o mieście.`]},{day: 24, title: `Zaproszenia i umawianie się`, title_native: `Convites e encontros`, focus: `Dziś nauczysz się zapraszać, proponować spotkanie i odpowiadać na propozycje. Przyda się to przy poznawaniu ludzi w hostelu, na kursie surfingu lub podczas wycieczki.`, vocab: [{pt: `encontro`, pl: `spotkanie`, ipa: `/ẽˈkõ.tɾu/`},{pt: `bar`, pl: `bar`, ipa: `/baʁ/`},{pt: `jantar`, pl: `kolacja / jeść kolację`, ipa: `/ʒɐ̃ˈtaʁ/`},{pt: `almoçar`, pl: `jeść obiad / lunch`, ipa: `/aɫ.muˈsaʁ/`},{pt: `beber`, pl: `pić`, ipa: `/bɨˈbeʁ/`},{pt: `sair`, pl: `wychodzić`, ipa: `/sɐˈiʁ/`},{pt: `hoje`, pl: `dziś`, ipa: `/ˈo.ʒɨ/`},{pt: `amanhã`, pl: `jutro`, ipa: `/ɐ.mɐˈɲɐ̃/`},{pt: `talvez`, pl: `może`, ipa: `/tɐlˈveʃ/`},{pt: `combinado`, pl: `umówione`, ipa: `/kõ.biˈna.du/`}], phrases: [{pt: `Quer tomar um café?`, pl: `Czy chce pan / pani wypić kawę?`, ipa: `/kɛʁ tuˈmaʁ ũ kɐˈfɛ/`},{pt: `Vamos jantar hoje?`, pl: `Zjemy dziś kolację?`, ipa: `/ˈva.muʃ ʒɐ̃ˈtaʁ ˈo.ʒɨ/`},{pt: `A que horas?`, pl: `O której godzinie?`, ipa: `/ɐ kɨ ˈɔ.ɾɐʃ/`},{pt: `Parece bom.`, pl: `Brzmi dobrze.`, ipa: `/pɐˈɾe.sɨ bõ/`},{pt: `Talvez amanhã.`, pl: `Może jutro.`, ipa: `/tɐlˈveʃ ɐ.mɐˈɲɐ̃/`},{pt: `Combinado.`, pl: `Umówione.`, ipa: `/kõ.biˈna.du/`}], grammar: `„Vamos…” może oznaczać „chodźmy” albo „zróbmy coś”, na przykład „Vamos jantar?” czyli „Zjemy kolację?”. „Quer…” to grzeczne „czy chce pan/pani…”. Odpowiedź „Combinado” jest naturalna, gdy plan został ustalony.`, practice: [`Zaproponuj kawę.`,`Zaproponuj kolację dziś wieczorem.`,`Zapytaj „o której?”.`,`Odpowiedz „brzmi dobrze”.`,`Odmów delikatnie, mówiąc „może jutro”.`]},{day: 25, title: `Poczta i wysyłanie rzeczy`, title_native: `Correio e envios`, focus: `Dziś przygotujesz się do wysłania pocztówki, paczki lub dokumentu. To przyda się na poczcie w Portugalii albo przy wysyłce pamiątek do Polski.`, vocab: [{pt: `correio`, pl: `poczta`, ipa: `/kuˈʁɐj.u/`},{pt: `postal`, pl: `pocztówka`, ipa: `/puʃˈtaɫ/`},{pt: `carta`, pl: `list`, ipa: `/ˈkaʁ.tɐ/`},{pt: `pacote`, pl: `paczka`, ipa: `/pɐˈkɔ.tɨ/`},{pt: `selo`, pl: `znaczek`, ipa: `/ˈse.lu/`},{pt: `endereço`, pl: `adres`, ipa: `/ẽ.dɨˈɾe.su/`},{pt: `enviar`, pl: `wysłać`, ipa: `/ẽ.viˈaʁ/`},{pt: `receber`, pl: `otrzymać`, ipa: `/ʁɨ.sɨˈbeʁ/`},{pt: `urgente`, pl: `pilne`, ipa: `/uʁˈʒẽ.tɨ/`},{pt: `normal`, pl: `zwykły`, ipa: `/nuʁˈmaɫ/`}], phrases: [{pt: `Onde fica o correio?`, pl: `Gdzie jest poczta?`, ipa: `/ˈõ.dɨ ˈfi.kɐ u kuˈʁɐj.u/`},{pt: `Queria enviar este postal.`, pl: `Chciałbym / chciałabym wysłać tę pocztówkę.`, ipa: `/kɨˈɾi.ɐ ẽ.viˈaʁ ˈeʃ.tɨ puʃˈtaɫ/`},{pt: `Preciso de um selo.`, pl: `Potrzebuję znaczka.`, ipa: `/pɾɨˈsi.zu dɨ ũ ˈse.lu/`},{pt: `Para a Polónia, por favor.`, pl: `Do Polski, proszę.`, ipa: `/pɐɾɐ ɐ puˈlɔ.njɐ puʁ fɐˈvoʁ/`},{pt: `É urgente?`, pl: `Czy to pilne?`, ipa: `/ɛ uʁˈʒẽ.tɨ/`},{pt: `Envio normal, por favor.`, pl: `Zwykła wysyłka, proszę.`, ipa: `/ẽˈvi.u nuʁˈmaɫ puʁ fɐˈvoʁ/`}], grammar: `„Para” przy wysyłaniu oznacza „do” kraju lub osoby. „Este” oznacza „ten” przy rzeczownikach męskich, a „esta” przy żeńskich, więc „este postal”, ale „esta carta”. W praktyce możesz wskazać przedmiot i powiedzieć „Queria enviar isto”.`, practice: [`Zapytaj, gdzie jest poczta.`,`Powiedz, że chcesz wysłać pocztówkę.`,`Poproś o znaczek do Polski.`,`Wybierz wysyłkę zwykłą.`,`Ułóż krótką rozmowę z pracownikiem poczty.`]},{day: 26, title: `Bankomat i pieniądze`, title_native: `Multibanco e dinheiro`, focus: `Dziś nauczysz się słownictwa związanego z bankomatem, wypłatą gotówki i płatnościami. W Portugalii często spotkasz słowo „Multibanco”.`, vocab: [{pt: `multibanco`, pl: `bankomat / system płatności w Portugalii`, ipa: `/muɫ.tiˈbɐ̃.ku/`},{pt: `caixa eletrônico`, pl: `bankomat, Brazylia`, ipa: `/ˈkaj.ʃɐ e.leˈtɾõ.ni.ku/`},{pt: `dinheiro`, pl: `gotówka / pieniądze`, ipa: `/diˈɲɐj.ɾu/`},{pt: `cartão`, pl: `karta`, ipa: `/kɐʁˈtɐ̃w/`},{pt: `banco`, pl: `bank`, ipa: `/ˈbɐ̃.ku/`},{pt: `levantar`, pl: `wypłacić, Portugalia`, ipa: `/lɨ.vɐ̃ˈtaʁ/`},{pt: `sacar`, pl: `wypłacić, Brazylia`, ipa: `/saˈkaʁ/`},{pt: `taxa`, pl: `opłata`, ipa: `/ˈta.ʃɐ/`},{pt: `recibo`, pl: `potwierdzenie / paragon`, ipa: `/ʁɨˈsi.bu/`},{pt: `senha`, pl: `PIN / hasło, Brazylia`, ipa: `/ˈse.ɲɐ/`}], phrases: [{pt: `Onde há um multibanco?`, pl: `Gdzie jest bankomat?`, ipa: `/ˈõ.dɨ a ũ muɫ.tiˈbɐ̃.ku/`},{pt: `Preciso levantar dinheiro.`, pl: `Muszę wypłacić gotówkę.`, ipa: `/pɾɨˈsi.zu lɨ.vɐ̃ˈtaʁ diˈɲɐj.ɾu/`},{pt: `Há alguma taxa?`, pl: `Czy jest jakaś opłata?`, ipa: `/a aɫˈɡu.mɐ ˈta.ʃɐ/`},{pt: `O cartão não funciona.`, pl: `Karta nie działa.`, ipa: `/u kɐʁˈtɐ̃w nɐ̃w fũˈsjɔ.nɐ/`},{pt: `Queria pagar com cartão.`, pl: `Chciałbym / chciałabym zapłacić kartą.`, ipa: `/kɨˈɾi.ɐ pɐˈɡaʁ kõ kɐʁˈtɐ̃w/`},{pt: `Pode imprimir o recibo?`, pl: `Czy może pan / pani wydrukować potwierdzenie?`, ipa: `/ˈpɔ.dɨ ĩ.pɾiˈmiʁ u ʁɨˈsi.bu/`}], grammar: `W Portugalii „levantar dinheiro” oznacza wypłacić gotówkę, choć dosłownie „podnieść pieniądze”. W Brazylii częstsze jest „sacar dinheiro”. „Não funciona” jest uniwersalne i znaczy „nie działa”, przy karcie, telefonie, aplikacji lub automacie.`, practice: [`Zapytaj, gdzie jest bankomat.`,`Powiedz, że musisz wypłacić gotówkę.`,`Zapytaj, czy jest opłata.`,`Powiedz, że karta nie działa.`,`Poproś o wydrukowanie potwierdzenia.`]},{day: 27, title: `Wynajem i zakwaterowanie`, title_native: `Aluguer e alojamento`, focus: `Dziś nauczysz się słów potrzebnych przy wynajmie pokoju, mieszkania lub samochodu. Przyda się to przy dłuższym pobycie w Portugalii albo Brazylii.`, vocab: [{pt: `aluguer`, pl: `wynajem, Portugalia`, ipa: `/ɐ.luˈɡeʁ/`},{pt: `aluguel`, pl: `wynajem, Brazylia`, ipa: `/a.luˈɡɛw/`},{pt: `apartamento`, pl: `mieszkanie`, ipa: `/ɐ.pɐʁ.tɐˈmẽ.tu/`},{pt: `casa`, pl: `dom`, ipa: `/ˈka.zɐ/`},{pt: `carro`, pl: `samochód, Brazylia`, ipa: `/ˈka.ʁu/`},{pt: `carro`, pl: `samochód, Portugalia`, ipa: `/ˈka.ʁu/`},{pt: `contrato`, pl: `umowa`, ipa: `/kõˈtɾa.tu/`},{pt: `depósito`, pl: `kaucja`, ipa: `/dɨˈpɔ.zi.tu/`},{pt: `chave`, pl: `klucz`, ipa: `/ˈʃa.vɨ/`},{pt: `limpo`, pl: `czysty`, ipa: `/ˈlĩ.pu/`}], phrases: [{pt: `Queria alugar um carro.`, pl: `Chciałbym / chciałabym wynająć samochód.`, ipa: `/kɨˈɾi.ɐ ɐ.luˈɡaʁ ũ ˈka.ʁu/`},{pt: `Tenho uma reserva para o apartamento.`, pl: `Mam rezerwację mieszkania.`, ipa: `/ˈte.ɲu ˈu.mɐ ʁɨˈzɛʁ.vɐ pɐɾɐ u ɐ.pɐʁ.tɐˈmẽ.tu/`},{pt: `Qual é o depósito?`, pl: `Jaka jest kaucja?`, ipa: `/kwaɫ ɛ u dɨˈpɔ.zi.tu/`},{pt: `Onde estão as chaves?`, pl: `Gdzie są klucze?`, ipa: `/ˈõ.dɨ ʃˈtɐ̃w ɐʃ ˈʃa.vɨʃ/`},{pt: `O quarto está limpo?`, pl: `Czy pokój jest czysty?`, ipa: `/u ˈkwaʁ.tu ʃˈta ˈlĩ.pu/`},{pt: `Preciso assinar o contrato?`, pl: `Czy muszę podpisać umowę?`, ipa: `/pɾɨˈsi.zu ɐ.siˈnaʁ u kõˈtɾa.tu/`}], grammar: `„Alugar” znaczy wynajmować, zarówno samochód, jak i mieszkanie. „Assinar” oznacza podpisać. Pytanie „Preciso…?” bez „de” przed czasownikiem znaczy „czy muszę…”, na przykład „Preciso assinar?”.`, practice: [`Powiedz, że chcesz wynająć samochód.`,`Zapytaj o kaucję.`,`Zapytaj, gdzie są klucze.`,`Zapytaj, czy musisz podpisać umowę.`,`Powiedz, że masz rezerwację mieszkania.`]},{day: 28, title: `Opinie i problemy`, title_native: `Opiniões e problemas`, focus: `Dziś nauczysz się mówić, co jest dobre, złe, zepsute albo nie tak. To przyda się w hotelu, restauracji, sklepie i przy wynajmie.`, vocab: [{pt: `bom`, pl: `dobry`, ipa: `/bõ/`},{pt: `boa`, pl: `dobra`, ipa: `/ˈbo.ɐ/`},{pt: `mau`, pl: `zły`, ipa: `/maw/`},{pt: `má`, pl: `zła`, ipa: `/ma/`},{pt: `problema`, pl: `problem`, ipa: `/pɾuˈble.mɐ/`},{pt: `sujo`, pl: `brudny`, ipa: `/ˈsu.ʒu/`},{pt: `suja`, pl: `brudna`, ipa: `/ˈsu.ʒɐ/`},{pt: `partido`, pl: `zepsuty / połamany`, ipa: `/pɐʁˈti.du/`},{pt: `barulhento`, pl: `hałaśliwy`, ipa: `/bɐ.ɾuˈʎẽ.tu/`},{pt: `calmo`, pl: `spokojny`, ipa: `/ˈkaɫ.mu/`}], phrases: [{pt: `Há um problema.`, pl: `Jest problem.`, ipa: `/a ũ pɾuˈble.mɐ/`},{pt: `O ar condicionado não funciona.`, pl: `Klimatyzacja nie działa.`, ipa: `/u aʁ kõ.di.sjuˈna.du nɐ̃w fũˈsjɔ.nɐ/`},{pt: `O quarto está sujo.`, pl: `Pokój jest brudny.`, ipa: `/u ˈkwaʁ.tu ʃˈta ˈsu.ʒu/`},{pt: `A chave está partida.`, pl: `Klucz jest zepsuty.`, ipa: `/ɐ ˈʃa.vɨ ʃˈta pɐʁˈti.dɐ/`},{pt: `Está muito barulhento.`, pl: `Jest bardzo hałaśliwie.`, ipa: `/ʃˈta ˈmũj.tu bɐ.ɾuˈʎẽ.tu/`},{pt: `Pode ajudar-me?`, pl: `Czy może mi pan / pani pomóc?`, ipa: `/ˈpɔ.dɨ ɐjˈu.daʁ mɨ/`}], grammar: `Przymiotniki dopasowują się do rzeczownika: „quarto sujo”, ale „chave partida”. „Não funciona” jest bezpiecznym zdaniem, gdy coś technicznego nie działa. Gdy zgłaszasz problem, zacznij od „Desculpe, há um problema”, żeby brzmieć uprzejmie.`, practice: [`Powiedz, że jest problem.`,`Powiedz, że klimatyzacja nie działa.`,`Powiedz, że pokój jest brudny.`,`Poproś o pomoc.`,`Zgłoś problem w hotelu w trzech grzecznych zdaniach.`]},{day: 29, title: `Przeszłość i doświadczenia`, title_native: `Passado e experiências`, focus: `Dziś nauczysz się prostych sposobów mówienia o tym, co już zrobiłeś lub zrobiłaś w podróży. Przyda się w rozmowie z lokalnymi osobami lub innymi podróżnikami.`, vocab: [{pt: `fui`, pl: `byłem / byłam / poszedłem / poszłam`, ipa: `/fuj/`},{pt: `vi`, pl: `widziałem / widziałam`, ipa: `/vi/`},{pt: `comi`, pl: `jadłem / jadłam`, ipa: `/kuˈmi/`},{pt: `bebi`, pl: `piłem / piłam`, ipa: `/bɨˈbi/`},{pt: `gostei`, pl: `podobało mi się`, ipa: `/ɡoʃˈtɐj/`},{pt: `visitei`, pl: `odwiedziłem / odwiedziłam`, ipa: `/vi.ziˈtɐj/`},{pt: `ontem`, pl: `wczoraj`, ipa: `/ˈõ.tẽj/`},{pt: `já`, pl: `już`, ipa: `/ʒa/`},{pt: `ainda`, pl: `jeszcze`, ipa: `/ɐˈĩ.dɐ/`},{pt: `nunca`, pl: `nigdy`, ipa: `/ˈnũ.kɐ/`}], phrases: [{pt: `Fui a Sintra ontem.`, pl: `Byłem / byłam wczoraj w Sintrze.`, ipa: `/fuj a ˈsĩ.tɾɐ ˈõ.tẽj/`},{pt: `Vi o mar.`, pl: `Widziałem / widziałam morze.`, ipa: `/vi u maʁ/`},{pt: `Comi peixe.`, pl: `Jadłem / jadłam rybę.`, ipa: `/kuˈmi ˈpɐj.ʃɨ/`},{pt: `Gostei muito.`, pl: `Bardzo mi się podobało.`, ipa: `/ɡoʃˈtɐj ˈmũj.tu/`},{pt: `Já visitei o museu.`, pl: `Już odwiedziłem / odwiedziłam muzeum.`, ipa: `/ʒa vi.ziˈtɐj u muˈzew/`},{pt: `Ainda não fui.`, pl: `Jeszcze nie byłem / byłam.`, ipa: `/ɐˈĩ.dɐ nɐ̃w fuj/`}], grammar: `Czas przeszły prosty jest bardzo częsty w rozmowie o podróży. Na początek zapamiętaj gotowe formy: „fui”, „vi”, „comi”, „gostei”. „Já” znaczy „już”, a „ainda não” znaczy „jeszcze nie”.`, practice: [`Powiedz, że wczoraj byłeś / byłaś w Sintrze.`,`Powiedz, że jadłeś / jadłaś rybę.`,`Powiedz, że bardzo Ci się podobało.`,`Powiedz, że już odwiedziłeś / odwiedziłaś muzeum.`,`Powiedz, że jeszcze nie byłeś / byłaś w jakimś miejscu.`]},{day: 30, title: `Podsumowanie podróżnika`, title_native: `Revisão do viajante`, focus: `Ostatni dzień łączy najważniejsze sytuacje: hotel, restaurację, transport, zakupy, zdrowie i rozmowę. Celem jest mówić prostymi zdaniami bez paniki podczas realnej podróży.`, vocab: [{pt: `preciso`, pl: `potrzebuję / muszę`, ipa: `/pɾɨˈsi.zu/`},{pt: `quero`, pl: `chcę`, ipa: `/ˈkɛ.ɾu/`},{pt: `posso`, pl: `mogę`, ipa: `/ˈpɔ.su/`},{pt: `tenho`, pl: `mam`, ipa: `/ˈte.ɲu/`},{pt: `gosto`, pl: `lubię`, ipa: `/ˈɡɔʃ.tu/`},{pt: `vou`, pl: `idę / jadę`, ipa: `/vo/`},{pt: `hoje`, pl: `dziś`, ipa: `/ˈo.ʒɨ/`},{pt: `amanhã`, pl: `jutro`, ipa: `/ɐ.mɐˈɲɐ̃/`},{pt: `aqui`, pl: `tutaj`, ipa: `/ɐˈki/`},{pt: `obrigado`, pl: `dziękuję, mówi mężczyzna`, ipa: `/obɾiˈɡa.du/`}], phrases: [{pt: `Preciso de ajuda.`, pl: `Potrzebuję pomocy.`, ipa: `/pɾɨˈsi.zu dɨ ɐjˈu.dɐ/`},{pt: `Quero ir para o centro.`, pl: `Chcę jechać do centrum.`, ipa: `/ˈkɛ.ɾu iʁ pɐɾɐ u ˈsẽ.tɾu/`},{pt: `Posso pagar com cartão?`, pl: `Czy mogę zapłacić kartą?`, ipa: `/ˈpɔ.su pɐˈɡaʁ kõ kɐʁˈtɐ̃w/`},{pt: `Tenho uma reserva.`, pl: `Mam rezerwację.`, ipa: `/ˈte.ɲu ˈu.mɐ ʁɨˈzɛʁ.vɐ/`},{pt: `Gosto muito desta cidade.`, pl: `Bardzo podoba mi się to miasto.`, ipa: `/ˈɡɔʃ.tu ˈmũj.tu ˈdeʃ.tɐ siˈda.dɨ/`},{pt: `Vou para o hotel agora.`, pl: `Jadę teraz do hotelu.`, ipa: `/vo pɐɾɐ u oˈtɛɫ ɐˈɡɔ.ɾɐ/`}], grammar: `Po 30 dniach masz już kilka „silników” do budowania zdań: „Preciso de…”, „Quero…”, „Posso…”, „Tenho…”, „Gosto de…”. W podróży nie musisz mówić perfekcyjnie; najważniejsze są krótkie, jasne zdania. Uprzejme „por favor”, „desculpe” i „obrigado/obrigada” sprawiają, że nawet proste zdania brzmią naturalnie.`, practice: [`Powiedz, że potrzebujesz pomocy.`,`Powiedz, że chcesz jechać do centrum.`,`Zapytaj, czy możesz zapłacić kartą.`,`Powiedz, że masz rezerwację.`,`Zbuduj mini-dialog łączący hotel, transport i kawiarnię.`]}];

var CONVERSATIONS_PL_PT = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Lizbonie rano. Chcesz zamówić kawę, pastel de nata i wodę, a na końcu zapłacić kartą.`, lines: [{who: `them`, pt: `Bom dia, o que deseja?`, pl: `Dzień dobry, czego pan / pani sobie życzy?`},{who: `you`, pt: `Bom dia, queria um café, por favor.`, pl: `Dzień dobry, poproszę kawę.`},{who: `them`, pt: `Claro, mais alguma coisa?`, pl: `Oczywiście, coś jeszcze?`},{who: `you`, pt: `Sim, um pastel de nata e uma água sem gás.`, pl: `Tak, pastel de nata i wodę niegazowaną.`},{who: `them`, pt: `Com açúcar no café?`, pl: `Z cukrem do kawy?`},{who: `you`, pt: `Não, sem açúcar, obrigado.`, pl: `Nie, bez cukru, dziękuję.`},{who: `them`, pt: `Está bem, pode sentar-se ali.`, pl: `Dobrze, może pan / pani usiąść tam.`},{who: `you`, pt: `Obrigado, quanto custa tudo?`, pl: `Dziękuję, ile wszystko kosztuje?`},{who: `them`, pt: `São seis euros.`, pl: `To sześć euro.`},{who: `you`, pt: `Posso pagar com cartão?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, pt: `Sim, claro.`, pl: `Tak, oczywiście.`},{who: `you`, pt: `Perfeito, obrigado.`, pl: `Świetnie, dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz do hotelu w Porto po południu. Masz rezerwację i chcesz zapytać o śniadanie oraz numer pokoju.`, lines: [{who: `them`, pt: `Boa tarde, bem-vindo ao hotel.`, pl: `Dzień dobry, witamy w hotelu.`},{who: `you`, pt: `Boa tarde, tenho uma reserva.`, pl: `Dzień dobry, mam rezerwację.`},{who: `them`, pt: `Qual é o seu nome, por favor?`, pl: `Jakie jest pana / pani nazwisko?`},{who: `you`, pt: `O meu nome é Kowalski.`, pl: `Nazywam się Kowalski.`},{who: `them`, pt: `Pode mostrar o seu documento?`, pl: `Czy może pan / pani pokazać dokument?`},{who: `you`, pt: `Claro, aqui está o meu passaporte.`, pl: `Oczywiście, oto mój paszport.`},{who: `them`, pt: `Obrigado, o seu quarto é o número vinte.`, pl: `Dziękuję, pana / pani pokój to numer dwadzieścia.`},{who: `you`, pt: `O pequeno-almoço está incluído?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, pt: `Sim, das sete às dez.`, pl: `Tak, od siódmej do dziesiątej.`},{who: `you`, pt: `Onde fica o elevador?`, pl: `Gdzie jest winda?`},{who: `them`, pt: `À direita, depois da receção.`, pl: `Po prawej, za recepcją.`},{who: `you`, pt: `Muito obrigado.`, pl: `Bardzo dziękuję.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Spacerujesz po Alfamie w Lizbonie i szukasz stacji metra. Zatrzymujesz lokalną osobę i prosisz o proste wskazówki.`, lines: [{who: `you`, pt: `Desculpe, onde fica a estação de metro?`, pl: `Przepraszam, gdzie jest stacja metra?`},{who: `them`, pt: `A estação fica perto daqui.`, pl: `Stacja jest blisko stąd.`},{who: `you`, pt: `Posso ir a pé?`, pl: `Czy mogę iść pieszo?`},{who: `them`, pt: `Sim, siga em frente.`, pl: `Tak, proszę iść prosto.`},{who: `you`, pt: `Depois viro à direita?`, pl: `Potem skręcam w prawo?`},{who: `them`, pt: `Não, vire à esquerda na praça.`, pl: `Nie, proszę skręcić w lewo na placu.`},{who: `you`, pt: `Pode mostrar no mapa?`, pl: `Czy może pan / pani pokazać na mapie?`},{who: `them`, pt: `Claro, está aqui.`, pl: `Oczywiście, jest tutaj.`},{who: `you`, pt: `É longe?`, pl: `Czy to daleko?`},{who: `them`, pt: `Não, são cinco minutos.`, pl: `Nie, to pięć minut.`},{who: `you`, pt: `Muito obrigado pela ajuda.`, pl: `Bardzo dziękuję za pomoc.`},{who: `them`, pt: `De nada, boa viagem.`, pl: `Nie ma za co, dobrej podróży.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Faro i chcesz zamówić danie bez mięsa. Pytasz o menu, składniki i rachunek.`, lines: [{who: `them`, pt: `Boa noite, tem reserva?`, pl: `Dobry wieczór, ma pan / pani rezerwację?`},{who: `you`, pt: `Boa noite, sim, tenho uma reserva para duas pessoas.`, pl: `Dobry wieczór, tak, mam rezerwację dla dwóch osób.`},{who: `them`, pt: `Perfeito, por aqui, por favor.`, pl: `Świetnie, tędy proszę.`},{who: `you`, pt: `Pode trazer o menu?`, pl: `Czy może pan / pani przynieść menu?`},{who: `them`, pt: `Claro, aqui está.`, pl: `Oczywiście, proszę.`},{who: `you`, pt: `Este prato tem carne?`, pl: `Czy to danie ma mięso?`},{who: `them`, pt: `Sim, tem frango.`, pl: `Tak, ma kurczaka.`},{who: `you`, pt: `Tem uma opção vegetariana?`, pl: `Czy jest opcja wegetariańska?`},{who: `them`, pt: `Sim, temos arroz com legumes e salada.`, pl: `Tak, mamy ryż z warzywami i sałatką.`},{who: `you`, pt: `Queria esse prato, por favor.`, pl: `Poproszę to danie.`},{who: `them`, pt: `Muito bem. Mais alguma coisa?`, pl: `Bardzo dobrze. Coś jeszcze?`},{who: `you`, pt: `Uma água com gás e depois a conta, por favor.`, pl: `Wodę gazowaną, a potem rachunek, proszę.`}]},{id: 5, title: `Kupowanie biletów na transport`, scene: `Jesteś na stacji w Porto i chcesz kupić bilet do centrum. Nie jesteś pewien / pewna, która linia jest właściwa.`, lines: [{who: `them`, pt: `Bom dia, precisa de ajuda?`, pl: `Dzień dobry, potrzebuje pan / pani pomocy?`},{who: `you`, pt: `Sim, queria um bilhete para o centro.`, pl: `Tak, poproszę bilet do centrum.`},{who: `them`, pt: `Só ida ou ida e volta?`, pl: `Tylko w jedną stronę czy tam i z powrotem?`},{who: `you`, pt: `Só ida, por favor.`, pl: `Tylko w jedną stronę, proszę.`},{who: `them`, pt: `Vai pagar com cartão?`, pl: `Zapłaci pan / pani kartą?`},{who: `you`, pt: `Sim, pago com cartão.`, pl: `Tak, płacę kartą.`},{who: `them`, pt: `A linha certa é a linha amarela.`, pl: `Właściwa linia to linia żółta.`},{who: `you`, pt: `A próxima paragem é o centro?`, pl: `Czy następny przystanek to centrum?`},{who: `them`, pt: `Não, são três paragens.`, pl: `Nie, to trzy przystanki.`},{who: `you`, pt: `Pode repetir, por favor?`, pl: `Czy może pan / pani powtórzyć?`},{who: `them`, pt: `Três paragens, linha amarela.`, pl: `Trzy przystanki, linia żółta.`},{who: `you`, pt: `Obrigado pela ajuda.`, pl: `Dziękuję za pomoc.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu w Lizbonie i chcesz kupić owoce oraz zapytać o cenę. Chcesz też zapłacić gotówką i poprosić o torbę.`, lines: [{who: `them`, pt: `Bom dia, deseja alguma coisa?`, pl: `Dzień dobry, życzy pan / pani sobie coś?`},{who: `you`, pt: `Bom dia, quanto custa isto?`, pl: `Dzień dobry, ile to kosztuje?`},{who: `them`, pt: `São três euros por quilo.`, pl: `To trzy euro za kilogram.`},{who: `you`, pt: `Queria meio quilo, por favor.`, pl: `Poproszę pół kilo.`},{who: `them`, pt: `Mais alguma coisa?`, pl: `Coś jeszcze?`},{who: `you`, pt: `Sim, estas maçãs também.`, pl: `Tak, te jabłka też.`},{who: `them`, pt: `Está bem, são cinco euros no total.`, pl: `Dobrze, razem pięć euro.`},{who: `you`, pt: `Pago em dinheiro.`, pl: `Płacę gotówką.`},{who: `them`, pt: `Claro, precisa de um saco?`, pl: `Oczywiście, potrzebuje pan / pani torby?`},{who: `you`, pt: `Sim, preciso de um saco, por favor.`, pl: `Tak, potrzebuję torby, proszę.`},{who: `them`, pt: `Aqui está.`, pl: `Proszę bardzo.`},{who: `you`, pt: `Obrigado, bom dia.`, pl: `Dziękuję, miłego dnia.`}]},{id: 7, title: `W aptece`, scene: `W Porto boli Cię głowa i szukasz apteki. Wchodzisz do farmacji, opisujesz problem i pytasz o lekarstwo.`, lines: [{who: `them`, pt: `Boa tarde, em que posso ajudar?`, pl: `Dzień dobry, w czym mogę pomóc?`},{who: `you`, pt: `Boa tarde, tenho dor de cabeça.`, pl: `Dzień dobry, boli mnie głowa.`},{who: `them`, pt: `Tem febre?`, pl: `Ma pan / pani gorączkę?`},{who: `you`, pt: `Não, não tenho febre.`, pl: `Nie, nie mam gorączki.`},{who: `them`, pt: `Tem alergia a algum remédio?`, pl: `Czy ma pan / pani alergię na jakieś lekarstwo?`},{who: `you`, pt: `Não, mas tenho alergia a nozes.`, pl: `Nie, ale mam alergię na orzechy.`},{who: `them`, pt: `Está bem, este remédio pode ajudar.`, pl: `Dobrze, to lekarstwo może pomóc.`},{who: `you`, pt: `Como tomo este remédio?`, pl: `Jak mam brać to lekarstwo?`},{who: `them`, pt: `Tome depois de comer.`, pl: `Proszę brać po jedzeniu.`},{who: `you`, pt: `Quanto custa?`, pl: `Ile kosztuje?`},{who: `them`, pt: `São oito euros.`, pl: `To osiem euro.`},{who: `you`, pt: `Obrigado pela ajuda.`, pl: `Dziękuję za pomoc.`}]},{id: 8, title: `Krótka rozmowa z lokalną osobą`, scene: `Siedzisz przy punkcie widokowym w Lizbonie i zaczynasz rozmowę z lokalną osobą. Rozmawiacie o mieście, podróży i planach na wieczór.`, lines: [{who: `you`, pt: `Olá, a vista é linda.`, pl: `Cześć, widok jest piękny.`},{who: `them`, pt: `Sim, é uma das melhores vistas da cidade.`, pl: `Tak, to jeden z najlepszych widoków w mieście.`},{who: `you`, pt: `Sou da Polónia e estou de férias.`, pl: `Jestem z Polski i jestem na wakacjach.`},{who: `them`, pt: `Que bom, gosta de Lisboa?`, pl: `Świetnie, podoba się panu / pani Lizbona?`},{who: `you`, pt: `Gosto muito daqui.`, pl: `Bardzo mi się tutaj podoba.`},{who: `them`, pt: `Já visitou Belém?`, pl: `Czy odwiedził pan / odwiedziła pani już Belém?`},{who: `you`, pt: `Ainda não, talvez amanhã.`, pl: `Jeszcze nie, może jutro.`},{who: `them`, pt: `Deve provar um pastel de nata lá.`, pl: `Powinien pan / pani spróbować tam pastel de nata.`},{who: `you`, pt: `Boa ideia, obrigado.`, pl: `Dobry pomysł, dziękuję.`},{who: `them`, pt: `Hoje há música ao vivo no centro.`, pl: `Dzisiaj jest muzyka na żywo w centrum.`},{who: `you`, pt: `Parece bom, a que horas?`, pl: `Brzmi dobrze, o której?`},{who: `them`, pt: `Às nove da noite.`, pl: `O dziewiątej wieczorem.`}]}];